   val maxIndex = n - 1
   val sieve = Array.fill(maxIndex + 1)(true)
   sieve(0) = false
   sieve(1) = false

   var i = 2
   while (i * i <= maxIndex) {
      if (sieve(i)) {
         for (j <- i * i to maxIndex by i) {
            sieve(j) = false
         }
      }
      i += 1
   }

   var sumA = 0L
   var sumB = 0L

   for (idx <- 0 until n) {
      if (sieve(idx)) {
         sumA += nums(idx)
      } else {
         sumB += nums(idx)
      }
   }

   Math.abs(sumA - sumB)
}
```

